(window.webpackJsonp=window.webpackJsonp||[]).push([[32],{659:function(r,n){r.exports='\x3c!-- \r\ntitle: 09-数据结构\r\nsort: \r\n--\x3e \r\n\r\n# 数据结构\r\n\r\n## 枚举\r\n\r\n```c\r\nenum COLOR {RED, GREEN, BLUE, colorNum};\r\nenum COLOR c = GREEN;\r\nprintf("%d %d %d", RED, colorNum, c);\r\n// 0 3 1\r\n```\r\n\r\n## 联合体\r\n\r\n> 每个实例只能存储一个声明的变量\r\n>\r\n> 最多只有一个成员有效\r\n\r\n```c\r\n#include <stdio.h>\r\n\r\nunion TestUnion\r\n{\r\n    char x;\r\n    int y;\r\n};\r\n\r\nint main(int argc, char const *argv[])\r\n{\r\n\r\n    union TestUnion test;\r\n    test.x = \'a\';\r\n    test.y = 404;\r\n    printf("size: %d\\nValue: %d", sizeof(test),test.y);\r\n    // size: 4\r\n\t// Value: 404\r\n\r\n    return 0;\r\n}\r\n```\r\n\r\n## 结构体\r\n\r\n> 请参考: `05-数组与指针`\r\n\r\n```c\r\n#include <stdio.h>\r\n\r\nint main()\r\n{\r\n\tstruct point {\r\n\t\tint x;\r\n\t\tint y;\r\n\t}place;\r\n    // struct point place;\r\n\tprintf("Input x,y: ");\r\n\tscanf("%d,%d",&place.x,&place.y);\r\n\tprintf("place is (%d,%d).",place.x,place.y);\r\n}\r\n\r\n# 还可使用 : num 定义结构体内元素占用空间大小\r\n```\r\n\r\n### 结构体指针\r\n\r\n```c\r\n#include <stdio.h>\r\n\r\nstruct point* StructInput(struct point *p);\r\n\r\nstruct point {\r\n\tint x;\r\n\tint y;\r\n};\r\n\r\nint main()\r\n{\r\n\tstruct point place;\r\n\t// StructInput(&place);\r\n    printf("x is: %d\\n",(*StructInput(&place)).x);\r\n\tprintf("place is (%d,%d).",place.x,place.y);\r\n}\r\n\r\nstruct point* StructInput(struct point *p)\r\n{\r\n\tprintf("Input x,y: ");\r\n\tscanf("%d,%d",&p->x,&(*p).y);\r\n\treturn p;\r\n}\r\n\r\n/*\r\nInput x,y: 3,4\r\nx is: 3\r\nplace is (3,4).\r\n*/\r\n```\r\n\r\n## 可变数组\r\n\r\n```c\r\n#include <stdio.h>\r\n#include <stdlib.h>\r\n\r\ntypedef struct\r\n{\r\n\tint *array;\r\n\tint size;\r\n} Array;\r\n\r\nArray array_creat(int init_size)\r\n{\r\n\tArray a;\r\n\ta.size = init_size;\r\n\ta.array = (int *)malloc(sizeof(int) * a.size);\r\n\treturn a;\r\n}\r\n\r\nvoid array_free(Array *a)\r\n{\r\n\tfree(a->array);\r\n\ta->array = NULL;\r\n\ta->size = 0;\r\n}\r\n\r\n\r\nArray array_icrease(Array *a, int increase)\r\n{\r\n\tArray new = array_creat(a->size+increase);\r\n\tfor(int i; i<a->size; i++)\r\n\t{\r\n\t\tnew.array[i] = a->array[i];\r\n\t}\r\n\tarray_free(a);\r\n\treturn new;\r\n}\r\n\r\n\r\nint array_size(Array *a)\r\n{\r\n\treturn a->size;\r\n}\r\n\r\nint array_get(Array *a, int index)\r\n{\r\n\treturn a->array[index];\r\n}\r\n\r\nArray array_input(Array *a, int index, int num)\r\n{\r\n\ta->array[index] = num;\r\n\treturn *a;\r\n}\r\n\r\nint main()\r\n{\r\n\tArray a = array_creat(100);\r\n\t// 批量赋值\r\n\tfor (int i; i < 100; i++)\r\n\t\tarray_input(&a, i, i);\r\n\t// 增加大小\r\n\ta = array_icrease(&a,20);\r\n\t// 打印信息\r\n\tprintf("ArraySize is %d.\\n", array_size(&a));\r\n\tprintf("Array[10] is %d.\\nArray[110] is %d.", array_get(&a, 10), array_get(&a, 110));\r\n\r\n\r\n\treturn 0;\r\n}\r\n\r\n/*\r\nArraySize is 120.\r\nArray[10] is 10.\r\nArray [110] is 0.\r\n*/\r\n```\r\n\r\n## 链表\r\n\r\n```c\r\n#include <stdio.h>\r\n#include <stdlib.h>\r\n\r\ntypedef struct LNode\r\n{\r\n\tint data;\r\n\tstruct LNode *next;\r\n} LNode, *LinkList;\r\n\r\nLinkList CreateList(int n);\r\nvoid print(LinkList h);\r\nint main()\r\n{\r\n\tLinkList Head = NULL;\r\n\tint n;\r\n\r\n\tscanf("%d", &n);\r\n\tHead = CreateList(n);\r\n\r\n\tprintf("Num is: \\n");\r\n\tprint(Head);\r\n\r\n\tprintf("\\n\\n");\r\n\tsystem("pause");\r\n\treturn 0;\r\n}\r\nLinkList CreateList(int n)\r\n{\r\n\tLinkList L, p, q;\r\n\tint i;\r\n\tL = (LNode *)malloc(sizeof(LNode));\r\n\tif (!L)\r\n\t\treturn 0;\r\n\tL->next = NULL;\r\n\tq = L;\r\n\tfor (i = 1; i <= n; i++)\r\n\t{\r\n\t\tp = (LinkList)malloc(sizeof(LNode));\r\n\t\tprintf("Input No_%d Value: ", i);\r\n\t\tscanf("%d", &(p->data));\r\n\t\tp->next = NULL;\r\n\t\tq->next = p;\r\n\t\tq = p;\r\n\t}\r\n\treturn L;\r\n}\r\nvoid print(LinkList h)\r\n{\r\n\tLinkList p = h->next;\r\n\twhile (p != NULL)\r\n\t{\r\n\t\tprintf("%d ", p->data);\r\n\t\tp = p->next;\r\n\t}\r\n}\r\n```\r\n\r\n'}}]);